    21	function getPoolMax(): number {
    22	  const configuredMax = Number.parseInt(
    23	    process.env.DATABASE_POOL_MAX ?? `${DEFAULT_POOL_MAX}`,
    24	    10,
    25	  );
    26	
    27	  if (Number.isNaN(configuredMax) || configuredMax < 1) {
    28	    throw new Error("DATABASE_POOL_MAX must be a positive integer.");
